void solve(int CASE)
{
	ll n, m, k; cin >> n >> m >> k;
	var h = vector<ll>(n + 1);
	var x = vector<ll>(n + 1);
	fa(i, 1, n)cin >> h[i];
	fa(i, 1, n)cin >> x[i];

	var check = [&](ll mid)->bool {
		// 要干掉第 i 个敌人，p 到 x[i] 的距离需 <= dis
		// dis = (mid * m - h[i]) / mid
		// 故 p 得在 [x[i] - dis, x[i] + dis] 的区间内才能干掉第 i 个敌人
		// 进行区间离散化差分

		var b = vector<int>();
		var p = vector<pii>(n + 1);
		fa(i, 1, n) {
			if (mid * m < h[i])continue;
			ll dis = (mid * m - h[i]) / mid;
			p[i] = { x[i] - dis, x[i] + dis };
			b.pb(p[i].px), b.pb(p[i].py);
			b.pb(p[i].px - 1), b.pb(p[i].py + 1);
		}

		sort(all(b));
		b.erase(unique(all(b)), b.end());
		int len = b.size();
		var find = [&](int value)->int {
			return upper_bound(all(b), value) - b.begin();
			};

		var cnt = vector<ll>(len + 2);
		fa(i, 1, n) {
			if (mid * m < h[i])continue;
			int l = find(p[i].px), r = find(p[i].py);
			cnt[l]++, cnt[r + 1]--;
		}
		fa(i, 1, len) {
			cnt[i] += cnt[i - 1];
			if (cnt[i] >= k)return 1;
		}
		return 0;
		};
	ll l = 1, r = 1e9, ans = 0;
	while (l <= r) {
		ll mid = l + r >> 1;
		if (check(mid)) {
			r = mid - 1;
			ans = mid;
		}
		else l = mid + 1;
	}
	if (ans)cout << ans << endl;
	else cout << -1 << endl;
	return;
}
